 24	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 25	import { isEmpty } from '@utils/utils';
 26	
 27	import { NO_RESULTS_VALUE } from './constants';
 28	import { handleMenuArrowKeys } from './utils';
 29	
 30	type ToggleProps = {
 31	  focusedItemIndex: null | number;
 32	  inputValue: string;
 33	  isOpen: boolean;
 34	  onSelect: (value: string) => void;
 35	  placeholder: string;
 36	  selected: string[];
 37	  selectOptions: SelectOptionProps[];
 38	  setFocusedItemIndex: (newValue: null | number) => void;
 39	  setInputValue: (newInput: string) => void;
 40	  setIsOpen: Dispatch<SetStateAction<boolean>>;
 41	  setSelected: (newSelection: string[]) => void;
 42	  textInputRef: RefObject<any>;
 43	  toggleRef: Ref<MenuToggleElement>;
 44	};
 45	
 46	const Toggle: FC<ToggleProps> = ({
 47	  focusedItemIndex,
 48	  inputValue,
 49	  isOpen,
 50	  onSelect,
 51	  placeholder,
 52	  selected,
 53	  selectOptions,
 54	  setFocusedItemIndex,
 55	  setInputValue,
 56	  setIsOpen,
 57	  setSelected,
 58	  textInputRef,
 59	  toggleRef,
 60	}) => {
 61	  const { t } = useNetworkingTranslation();
 62	
 63	  const onInputKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
 64	    const enabledMenuItems = selectOptions.filter((menuItem) => !menuItem.isDisabled);
 65	    const [firstMenuItem] = enabledMenuItems;
 66	    const focusedItem = focusedItemIndex ? enabledMenuItems?.[focusedItemIndex] : firstMenuItem;
 67	
 68	    switch (event.key) {
 69	      // Select the first available option
 70	      case 'Enter':
 71	        if (!isOpen) {
 72	          setIsOpen((prevIsOpen) => !prevIsOpen);
 73	          return;
 74	        }
 75	
 76	        if (isOpen && focusedItem.value !== NO_RESULTS_VALUE) {
 77	          onSelect(focusedItem.value as string);
 78	        }
 79	
 80	        break;
 81	      case 'Tab':
 82	      case 'Escape':
 83	        setIsOpen(false);
 84	        break;
 85	      case 'ArrowUp':
 86	      case 'ArrowDown':
 87	        event.preventDefault();
 88	
 89	        if (isOpen) {
 90	          const indexToFocus = handleMenuArrowKeys(event.key, focusedItemIndex, selectOptions);
 91	
 92	          if (indexToFocus !== null) setFocusedItemIndex(indexToFocus);
 93	        }
 94	        break;
 95	    }
 96	  };
 97	
 98	  const onToggleClick = () => {
 99	    setIsOpen(!isOpen);
100	  };
101	
102	  const onTextInputChange = (_event: FormEvent<HTMLInputElement>, value: string) => {
103	    setInputValue(value);
104	    setFocusedItemIndex(null);
105	
106	    if (value) setIsOpen(true);
107	  };
108	
109	  return (
110	    <MenuToggle
111	      innerRef={toggleRef}
112	      isExpanded={isOpen}
113	      isFullWidth
114	      onClick={onToggleClick}
115	      variant="typeahead"
116	    >
117	      <TextInputGroup isPlain>
118	        <TextInputGroupMain
119	          aria-controls="select-multi-typeahead-listbox"
120	          autoComplete="off"
121	          id="multi-typeahead-select-input"
122	          innerRef={textInputRef}
123	          isExpanded={isOpen}
124	          onChange={onTextInputChange}
125	          onClick={onToggleClick}
126	          onKeyDown={onInputKeyDown}
127	          placeholder={placeholder}
128	          role="combobox"
129	          value={inputValue}
130	        >
131	          <ChipGroup aria-label={t('Current selections')}>
132	            {selected?.map((selection, index) => (
133	              <Chip
134	                key={index}
135	                onClick={(ev) => {
136	                  ev.stopPropagation();
137	                  onSelect(selection);
138	                }}
139	              >
140	                {selection}
141	              </Chip>
142	            ))}
143	          </ChipGroup>
144	        </TextInputGroupMain>
145	        <TextInputGroupUtilities>
146	          {!isEmpty(selected) && (
147	            <Button
148	              aria-label={t('Clear input value')}
149	              onClick={() => {
150	                setInputValue('');
151	                setSelected([]);
152	                textInputRef?.current?.focus();
153	              }}
154	              variant={ButtonVariant.plain}
155	            >
156	              <TimesIcon aria-hidden />
157	            </Button>
158	          )}
159	        </TextInputGroupUtilities>
160	      </TextInputGroup>
161	    </MenuToggle>
162	  );
163	};
164	
165	export default Toggle;

